mapper.select:
SELECT COUNT(*)
FROM t_sales_price t

    AND t.f_number = #{price.fNumber}
    AND t.f_name LIKE CONCAT('%', #{price.fName}, '%')
    AND t.f_khjc LIKE CONCAT('%', #{price.fKhjc}, '%')
    AND t.f_price_type = #{price.fPriceType}
    AND t.f_currency_id = #{price.fCurrencyId}
    AND t.f_effective_date = #{price.fEffectiveDate}
    AND t.f_expiry_date = #{price.fExpiryDate}
